const item = $input.first().json;
const t = new Date().toISOString();
var upstream=item.upstream_outputs||{};
var keys=Object.keys(upstream);
var pMetrics=keys.map(function(k){var p=upstream[k]||{};return{persona:p.persona_name||k,status:p.status||'unknown',duration_ms:(p.metrics&&p.metrics.duration_ms)||0};});
var totalDur=pMetrics.reduce(function(s,p){return s+p.duration_ms;},0);
var metrics={persona_metrics:pMetrics,total_personas:keys.length,total_duration_ms:totalDur,failed_count:pMetrics.filter(function(p){return p.status==='failed';}).length,blocked_count:pMetrics.filter(function(p){return p.status==='blocked';}).length};
var prompt='Role: Dev Intelligence analyst. JSON only, no markdown.\nMETRICS: '+JSON.stringify(metrics)+'\nUPSTREAM_KEYS: '+JSON.stringify(keys)+'\nReturn this exact JSON:\n'+JSON.stringify({request_id:item.request_id||'unknown',persona_name:'AG_09_DEV_INTELLIGENCE',status:'success|failed',summary:'<1 sentence>',structured_output:{total_personas:metrics.total_personas,total_ms:metrics.total_duration_ms,health_score:0,bottlenecks:[{persona:'<str>',issue:'<str>'}],git_summary:'<1 paragraph>',doc_summary:'<1 paragraph>',improvement_suggestions:[]},assumptions:[],risks:[],blocking_questions:[],handoff_recommendation:{next_personas:['AG_10_RESPONSE_FORMATTER'],reason:'metrics ready'},metrics:{started_at:''+t,ended_at:'',duration_ms:0,iteration_count:1}});
var apiBody = {model:'claude-haiku-4-5-20251001',max_tokens:1024,messages:[{role:'user',content:prompt}]};
return [{json:{...item,apiBody,started_at:t,computed_metrics:metrics}}];

const item = $input.first().json;
const end = new Date().toISOString();
const start = item.started_at || end;
let rawText = '';
try {
  if (item.content && Array.isArray(item.content)) { rawText = item.content[0].text || ''; }
  else if (typeof item.content === 'string') { rawText = item.content; }
} catch(e) {}
let out;
try { var m=rawText.match(/\{[\s\S]*\}/); out=m?JSON.parse(m[0]):{error:'parse_failed',raw:rawText.slice(0,400)}; }
catch(e){ out={error:e.message,raw:rawText.slice(0,400)}; }
var dur=Math.max(0,new Date(end)-new Date(start));
if(out.metrics){out.metrics.ended_at=end;out.metrics.duration_ms=dur;}
return [{json:{
  request_id:item.request_id||'unknown',
  persona_name:out.persona_name||'UNKNOWN',
  status:out.error?'failed':(out.status||'success'),
  summary:out.summary||'Complete.',
  structured_output:out.structured_output||out,
  assumptions:out.assumptions||[],
  risks:out.risks||[],
  blocking_questions:out.blocking_questions||[],
  handoff_recommendation:out.handoff_recommendation||{next_personas:[],reason:'done'},
  metrics:{started_at:start,ended_at:end,duration_ms:dur,iteration_count:1}
}}];
